/******************************
 * Fields Validation
 * 
 * by Helen Callisaya
 * modified by Cinthia Romero
 *****************************/

function valueIsValid(value) {
    return (value !== null && value !== "" && value !== 0 && value !== [] && (typeof value !== "undefined"));
}

let fieldsValidation = {
    isValid: true,
	isValidCounsel: true,
	messageCounsel: "",
	isValidExternal: true,
	messageExternal: "",
};
//Validate Address tax requirements and engage outside counsel
if (!this.PE_TAX_COUNSEL_NOT_APPLICABLE) {
	if (!valueIsValid(this.PE_TAX_COUNSEL_COMPANY_NAME)) {
		fieldsValidation.isValidCounsel = false;
	}
	if (!valueIsValid(this.PE_TAX_COUNSEL_CONTACT_NAME)) {
		fieldsValidation.isValidCounsel = false;
	}
	if (Array.isArray(this.PE_TAX_COUNSEL_EMAIL_TABLE) && this.PE_TAX_COUNSEL_EMAIL_TABLE.length <= 0) {
		fieldsValidation.isValidCounsel = false;
		fieldsValidation.messageCounsel = "At least one row is required";
	} else {
		let i = 0;
		let counselEmailOK = "YES";
		this.PE_TAX_COUNSEL_EMAIL_TABLE.forEach(row => {
			i++;
			if (!valueIsValid(row.PE_TAX_COUNSEL_EMAIL)) {				
				fieldsValidation.isValidCounsel = false;
				counselEmailOK = "NO";
			}
		});
		if (counselEmailOK == "NO") {
			fieldsValidation.messageCounsel = "Please enter a valid value in all email rows";
		}
	}
}
//Validate Additional External Tax Counsel Contact Information
if (!this.PE_EXTERNAL_TAX_COUNSEL_NOT_APPLICABLE) {
	if (!valueIsValid(this.PE_EXTERNAL_TAX_COUNSEL_COMPANY_NAME)) {
		fieldsValidation.isValidExternal = false;
	}
	if (!valueIsValid(this.PE_EXTERNAL_TAX_COUNSEL_CONTACT_NAME)) {
		fieldsValidation.isValidExternal = false;
	}
	if (Array.isArray(this.PE_EXTERNAL_TAX_COUNSEL_EMAIL_TABLE) && this.PE_EXTERNAL_TAX_COUNSEL_EMAIL_TABLE.length <= 0) {
		fieldsValidation.isValidExternal = false;
		fieldsValidation.messageExternal = "At least one row is required";
	} else {
		let i = 0;
		let externalEmailsOk = "YES";
		this.PE_EXTERNAL_TAX_COUNSEL_EMAIL_TABLE.forEach(row => {
			i++;
			if (!valueIsValid(row.PE_EXTERNAL_TAX_COUNSEL_EMAIL)) {
				fieldsValidation.isValidExternal = false;
				externalEmailsOk = "NO";
			}
		});
		if (externalEmailsOk == "NO") {
			fieldsValidation.messageExternal = "Please enter a valid value in all email rows";
		}
	}
}
if (!fieldsValidation.isValidCounsel || !fieldsValidation.isValidExternal) {
	fieldsValidation.isValid = false;
} 
if (this.PE_SAVE_SUBMIT_TX1 == 'SAVE') {
	fieldsValidation.isValidCounsel = true;
	fieldsValidation.isValidExternal = true;
}
return fieldsValidation;
